458	// ── HTML 看板 ──
459	generateDashboard(enhanced);
460	
461	function generateDashboard(data) {
462	  const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
463	  const now = new Date();
464	  const today = now.toISOString().slice(0, 10);
465	  const timeStr = now.toLocaleString('zh-CN');
466	
467	  const byStage = {};
468	  for (const e of data) { const k = e.stageLabel || '待分类'; if (!byStage[k]) byStage[k] = []; byStage[k].push(e); }
469	
470	  // 静默分级
471	  const silenceTiers = [
472	    { label: '近期活跃 <3天', color: '#27ae60', maxD: 3 },
473	    { label: '近期活跃 3-7天', color: '#27ae60', maxD: 7, minD: 3 },
474	    { label: '短期静默 7-14天', color: '#3498db', maxD: 14, minD: 7 },
475	    { label: '中期静默 14-30天', color: '#f39c12', maxD: 30, minD: 14 },
476	    { label: '长期静默 30-90天', color: '#e67e22', maxD: 90, minD: 30 },
477	    { label: '沉淀 90天+', color: '#c0392b', maxD: 99999, minD: 90 },
478	  ];
479	  const silenceGroups = {};
480	  for (const tier of silenceTiers) silenceGroups[tier.label] = [];
481	  for (const e of data) {
482	    const d = e.lastCustomerMsgDays === '-' ? 9999 : e.lastCustomerMsgDays;
483	    for (const tier of silenceTiers) {
484	      if (d < tier.maxD && (tier.minD === undefined || d >= tier.minD)) {
485	        silenceGroups[tier.label].push(e);
486	        break;
487	      }
488	    }
489	  }
490	
491	  // KPI
492	  const total = data.length;
493	  const active3d = data.filter(e => e.lastCustomerMsgDays !== '-' && e.lastCustomerMsgDays < 3).length;
494	  const silent90p = data.filter(e => e.lastCustomerMsgDays !== '-' && e.lastCustomerMsgDays >= 90).length;
495	  const unread = data.filter(e => e.questionUnanswered).length;
496	  const changedCount = data.filter(e => e.daysAgo <= 3).length;
497	  const needsAction = data.filter(e => e.stageLabel === '待回复' || e.questionUnanswered || e.stageLabel === 'PI已发' || (e.stageLabel === '报价已发' && e.lastCustomerMsgDays !== '-' && e.lastCustomerMsgDays <= 7)).length;
498	
499	  const kpiCards = [
500	    { num: total, label: '总客户', color: '#1a5276' },
501	    { num: active3d, label: '3天活跃', color: '#1a5276' },
502	    { num: silent90p, label: '超90天无互动', color: '#c0392b' },
503	    { num: unread, label: '未读消息', color: '#e67e22' },
504	    { num: changedCount, label: '本期变动', color: '#27ae60' },
505	    { num: needsAction, label: '需行动', color: '#8e44ad' },
506	  ];
507	
508	  // 双轴矩阵 (生命周期 × 质量)
509	  const stageOrder = ['待回复', '初询沟通', '报价已发', '谈判/样品', 'PI已发', '订单执行中', '已签收', '售后'];
510	  const gradeOrder = ['S', 'A', 'B', 'C', 'D'];
511	  const matrixData = {};
512	  for (const s of stageOrder) {
513	    matrixData[s] = {};
514	    for (const g of gradeOrder) matrixData[s][g] = [];
515	  }
516	  for (const e of data) {
517	    const s = e.stageLabel || '待分类';
518	    const g = e.grade || 'D';
519	    if (matrixData[s] && matrixData[s][g]) {
520	      matrixData[s][g].push(e);
521	    }
522	  }
523	
524	  const actions = {
525	    '待回复': { label: '待回复', byQuality: { S:'优先回复，搜索客户品牌/渠道背景后定制话术', A:'24h内回复，附工厂认证+大牌合作案例', B:'24h内回复，标准模板确认需求', C:'24h内回复，简要确认需求', D:'确认是否真实询盘后回复' }, defaultAction: '客户发来消息未回复，24小时内首次响应' },
526	    '初询沟通': { label: '初询沟通', byQuality: { S:'研究客户品牌/店铺/渠道，定制话术，建立"同级别工厂伙伴"认知', A:'发送精选目录+工厂认证+BSCI/ISO证书，推进需求确认', B:'标准目录发送，确认MOQ和产品需求', C:'简要回复，对方表达需求后再深挖', D:'确认是否真实询盘，标准模板回复' }, defaultAction: '了解客户需求，发送目录/工厂资料' },
527	    '报价已发': { label: '报价已发', byQuality: { S:'48h跟进，每次带新信息/价值（新品/案例/市场数据）', A:'48h跟进，附相关产品推荐或同行案例', B:'3-5天温和提醒，确认是否收到报价', C:'3-5天提醒一次，3轮无回应转入沉默管理', D:'5-7天一次，标准提醒' }, defaultAction: '跟进报价反馈，解答疑问' },
528	    '谈判/样品': { label: '谈判/样品', byQuality: { S:'主动做mockup/方案，不等客户开口，48h跟进', A:'关注样品反馈/价格谈判进展，48h确认状态', B:'确认是否需调整报价或规格，48-72h跟进', C:'对方确认意向后才做额外方案', D:'跟进但不投入过多定制资源' }, defaultAction: '推动决策，解决疑虑' },
529	    'PI已发': { label: 'PI已发', byQuality: { S:'PI发出48h确认收到，第5天提醒付款，第7天催款', A:'PI发出48h确认收到，第5天提醒，PI到期前提醒', B:'48h确认收到，PI有效期结束前提醒', C:'确认收到，到期前提醒一次', D:'确认收到即可' }, defaultAction: '确认PI收到，跟进付款' },
530	    '订单执行中': { label: '订单执行中', byQuality: { S:'每周主动同步进度，拍照/视频，关键节点提前通知', A:'每周同步，关键节点通知', B:'关键节点通知（排产/发货）', C:'发货时通知', D:'发货时通知' }, defaultAction: '关键节点主动通知（排产/完成/发货）' },
531	    '已签收': { label: '已签收', byQuality: { S:'签收7天回访，同步新品+定制方案，争取复购', A:'签收7天回访，发新品目录', B:'签收7天回访，确认满意度', C:'签收后回访一次', D:'签收后回访一次' }, defaultAction: '确认收货满意，推动复购' },
532	    '售后': { label: '售后', byQuality: { S:'≤1h响应，主动提供补偿方案', A:'≤1h响应，24h内给方案', B:'24h响应', C:'24h内回复', D:'24h内回复' }, defaultAction: '快速响应，妥善处理' },
533	  };
534	
535	  // 构建静默HTML
536	  const silenceHtml = silenceTiers.map(tier => {
537	    const items = silenceGroups[tier.label] || [];
538	    if (items.length === 0) return '';
539	    const itemsHtml = items.sort((a, b) => {
540	      const da = a.lastCustomerMsgDays === '-' ? 9999 : a.lastCustomerMsgDays;
541	      const db = b.lastCustomerMsgDays === '-' ? 9999 : b.lastCustomerMsgDays;
542	      return da - db;
543	    }).map(e => {
544	      const d = e.lastCustomerMsgDays === '-' ? '?' : e.lastCustomerMsgDays;
545	      return '<div style="display:flex;justify-content:space-between;padding:2px 0;font-size:11px;"><span>' + esc(e.name) + ' <span style="color:var(--text-secondary);">' + esc(e.country || '??') + '</span></span><span>' + d + '天</span></div>';
546	    }).join('');
547	    return '<div>' +
548	      '<div onclick="var d=this.nextElementSibling;d.style.display=d.style.display===\'block\'?\'none\':\'block\'" style="display:flex;justify-content:space-between;align-items:center;padding:10px 14px;border-bottom:1px solid var(--border);cursor:pointer;">' +
549	      '<span>● <strong style="color:' + tier.color + ';">' + tier.label + '</strong></span>' +
550	      '<strong style="font-size:16px;color:' + tier.color + ';">' + items.length + '</strong></div>' +
551	      '<div style="display:none;padding:8px 14px;background:rgba(' + (tier.color === '#27ae60' ? '39,174,96' : tier.color === '#3498db' ? '52,152,219' : tier.color === '#f39c12' ? '243,156,18' : tier.color === '#e67e22' ? '230,126,34' : '192,57,43') + ',0.08);border-bottom:1px solid var(--border);">' + itemsHtml + '</div></div>';
552	  }).filter(Boolean).join('');
553	
554	  // 市场分布
555	  const coreMarkets = ['SD', 'EG', 'CD', 'ZM', 'CI', 'SA', 'AE'];
556	  const coreNames = { SD:'苏丹', EG:'埃及', CD:'刚果民主', ZM:'赞比亚', CI:'科特迪瓦', SA:'沙特', AE:'阿联酋' };
557	  const marketData = {};
558	  for (const mk of coreMarkets) marketData[mk] = { count: 0, sa: 0, action: 0 };
559	  for (const e of data) {
560	    const c = e.country || '';
561	    if (marketData[c] !== undefined) {
562	      marketData[c].count++;
563	      if (e.grade === 'S' || e.grade === 'A') marketData[c].sa++;
564	      if (e.stageLabel === '待回复' || e.questionUnanswered || e.stageLabel === 'PI已发') marketData[c].action++;
565	    }
566	  }
567	  const marketRows = coreMarkets.filter(mk => marketData[mk].count > 0).map(mk => {
568	    const md = marketData[mk];
569	    return '<tr><td style="padding:8px;border:1px solid var(--border);font-weight:600;">' + coreNames[mk] + '</td>' +
570	      '<td style="text-align:center;padding:8px;border:1px solid var(--border);">' + md.count + '</td>' +
571	      '<td style="text-align:center;padding:8px;border:1px solid var(--border);">' + md.sa + '</td>' +
572	      '<td style="text-align:center;padding:8px;border:1px solid var(--border);color:#c0392b;font-weight:bold;">' + md.action + '</td></tr>';
573	  }).join('');
574	
575	  // 矩阵表格行
576	  const matrixRows = stageOrder.map(s => {
577	    const cells = gradeOrder.map(g => {
578	      const items = matrixData[s] ? (matrixData[s][g] || []) : [];
579	      const n = items.length;
580	      if (n === 0) return '<td style="text-align:center;padding:6px 8px;border:1px solid var(--border);color:var(--text-tertiary);">0</td>';
581	      let opacity = Math.min(0.5, 0.15 + n * 0.005);
582	      if (g === 'S') opacity = Math.min(0.5, 0.2 + n * 0.02);
583	      return '<td style="text-align:center;padding:6px 8px;border:1px solid var(--border);cursor:pointer;background:rgba(255,159,10,' + opacity + ');font-weight:600;" onclick="openModal(\'' + s + '\',\'' + g + '\')">' + n + '</td>';
584	    }).join('');
585	    return '<tr><td class="rl">' + s + '</td>' + cells + '</tr>';
586	  }).join('');
587	
588	  // 构建 MATRIX JSON (简化版，只含展示所需)
589	  const matrixJson = {};
590	  for (const s of stageOrder) {
591	    matrixJson[s] = {};
592	    for (const g of gradeOrder) {
593	      matrixJson[s][g] = (matrixData[s][g] || []).map(e => ({
594	        n: e.name,
595	        c: e.countryCN || e.country || '??',
596	        d: e.lastCustomerMsgDays === '-' ? 999 : e.lastCustomerMsgDays,
597	        g: e.grade,
598	        as: e.afterSalesFlag || false,
599	        st: e.actionStatus || '',
600	        ac: e.actionText || '',
601	        pr: e.actionPriority || 'idle'
602	      }));
603	    }
604	  }
605	
606	  const html = '<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n<meta charset="utf-8">\n<title>OKKI 客户管道看板 — ' + today + '</title>\n' +
607	'<style>\n' +
608	'  :root { --bg-primary: #f5f5f7; --bg-secondary: #ffffff; --bg-tertiary: #e5e5e7; --border: #d1d1d6;\n' +
609	'    --text-primary: #1d1d1f; --text-secondary: #86868b; --text-tertiary: #aeaeb2;\n' +
610	'    --accent: #0071e3; --success: #34c759; --warning: #ff9f0a; --error: #ff3b30; }\n' +
611	'  @media (prefers-color-scheme: dark) {\n' +
612	'    :root { --bg-primary: #1d1d1f; --bg-secondary: #2d2d2f; --bg-tertiary: #3d3d3f;\n' +
613	'      --border: #424245; --text-primary: #f5f5f7; --text-secondary: #86868b;\n' +
614	'      --text-tertiary: #636366; --accent: #0a84ff; }\n' +
615	'  }\n' +
616	'  * { box-sizing: border-box; margin: 0; padding: 0; }\n' +
617	'  body { font-family: system-ui, -apple-system, BlinkMacSystemFont, sans-serif;\n' +
618	'    background: var(--bg-primary); color: var(--text-primary); line-height: 1.5;\n' +
619	'    padding: 20px 24px; max-width: 1400px; margin: 0 auto; }\n' +
620	'  h1 { font-size: 1.3rem; margin-bottom: 4px; }\n' +
621	'  .subtitle { color: var(--text-secondary); font-size: 0.85rem; margin-bottom: 20px; }\n' +
622	'  .kpi-grid { display: grid; grid-template-columns: repeat(6, 1fr); gap: 10px; margin-bottom: 20px; }\n' +
623	'  .kpi { color: #fff; padding: 14px 12px; border-radius: 8px; text-align: center; }\n' +
624	'  .kpi .num { font-size: 28px; font-weight: 700; }\n' +
625	'  .kpi .lbl { font-size: 11px; opacity: 0.9; }\n' +
626	'  .card { background: var(--bg-secondary); border: 1px solid var(--border); border-radius: 10px; overflow: hidden; margin-bottom: 16px; }\n' +
627	'  .card-hd { background: var(--bg-tertiary); padding: 10px 14px; font-weight: 600; font-size: 13px; border-bottom: 1px solid var(--border); }\n' +
628	'  .card-hd span { font-weight: normal; font-size: 11px; color: var(--text-secondary); }\n' +
629	'  table.mx { width: 100%; border-collapse: collapse; font-size: 12px; }\n' +
630	'  table.mx th { padding: 6px 8px; border: 1px solid var(--border); background: var(--bg-tertiary); font-weight: 600; }\n' +
631	'  table.mx td { border: 1px solid var(--border); }\n' +
632	'  table.mx td.rl { text-align: center; font-weight: 600; padding: 6px 4px; width:64px; font-size:11px; }\n' +
633	'  .flex { display: flex; gap: 16px; margin-bottom: 16px; }\n' +
634	'  .flex-1 { flex: 1; }\n' +
635	'  .flex-320 { flex: 0 0 340px; }\n' +
636	'  table.sub { width: 100%; border-collapse: collapse; font-size: 12px; }\n' +
637	'  table.sub th { padding: 8px; border: 1px solid var(--border); text-align: left; background: var(--bg-tertiary); font-weight: 600; }\n' +
638	'  table.sub td { padding: 8px; border: 1px solid var(--border); }\n' +
639	'  .trend-row { display: flex; justify-content: space-between; align-items: center; padding: 6px 0; border-bottom: 1px solid var(--border); }\n' +
640	'  .trend-row .det { font-size: 11px; color: var(--text-secondary); }\n' +
641	'  .footer { margin-top: 24px; padding: 14px; border-top: 1px solid var(--border); font-size: 11px; color: var(--text-secondary); text-align: center; }\n' +
642	'  .footer a { color: var(--accent); }\n' +
643	'  .modal-overlay { display:none; position:fixed; top:0; left:0; right:0; bottom:0; background:rgba(0,0,0,0.45); z-index:9999; justify-content:center; align-items:center; }\n' +
644	'  .modal-overlay.show { display:flex; }\n' +
645	'  .modal-box { background:var(--bg-secondary); border-radius:10px; width:700px; max-width:92vw; max-height:75vh; overflow-y:auto; box-shadow:0 8px 30px rgba(0,0,0,0.25); }\n' +
646	'  @media (prefers-color-scheme: dark) { .modal-box { box-shadow:0 8px 30px rgba(0,0,0,0.6); } }\n' +
647	'  .modal-hd { display:flex; justify-content:space-between; align-items:center; padding:14px 18px; border-bottom:1px solid var(--border); font-weight:600; font-size:15px; position:sticky; top:0; background:var(--bg-secondary); border-radius:10px 10px 0 0; z-index:1; }\n' +
648	'  .modal-close { cursor:pointer; font-size:20px; color:var(--text-secondary); line-height:1; padding:0 4px; border:none; background:none; }\n' +
649	'  .modal-close:hover { color:var(--text-primary); }\n' +
650	'  .modal-body { padding:14px 18px; }\n' +
651	'  .modal-body table { width:100%; border-collapse:collapse; font-size:12px; }\n' +
652	'  .modal-body th { padding:6px 8px; border:1px solid var(--border); background:var(--bg-tertiary); text-align:left; font-weight:600; }\n' +
653	'  .modal-body td { padding:6px 8px; border:1px solid var(--border); }\n' +
654	'</style>\n</head>\n<body>\n\n' +
655	'<h1>OKKI 客户管道看板</h1>\n' +
656	'<div class="subtitle">生成时间：' + timeStr + ' | 数据源：s1_classification.json + chat_history | 全覆盖 ' + total + ' 客户</div>\n\n' +
657	'<div class="kpi-grid">\n' +
658	  kpiCards.map(c => '<div class="kpi" style="background:' + c.color + ';"><div class="num">' + c.num + '</div><div class="lbl">' + c.label + '</div></div>').join('\n') + '\n</div>\n\n' +
659	'<div class="card">\n  <div class="card-hd">客户双轴矩阵 <span>（生命周期 × 质量）— 点击格子展开客户名单 + 标准动作</span></div>\n' +
660	'  <div style="overflow-x:auto;">\n    <table class="mx">\n      <tr><th style="text-align:center;width:64px;">阶段 \\ 等级</th><th>S</th><th>A</th><th>B</th><th>C</th><th>D</th></tr>\n' +
661	'      ' + matrixRows + '\n    </table>\n  </div>\n' +
662	'  <div style="padding:6px 14px;font-size:10px;color:var(--text-secondary);">颜色越深=该格客户越多 | 点击数字弹出详情（标准动作 + 客户名单）</div>\n</div>\n\n' +
663	'<div class="flex">\n  <div class="flex-320 card">\n    <div class="card-hd">静默风险分级</div>\n    <div>\n    ' + silenceHtml + '\n    </div>\n  </div>\n' +
664	'  <div class="flex-1 card" style="align-self:flex-start;">\n    <div class="card-hd">本期变动（相较上次运行）</div>\n' +
665	'    <div style="padding:10px 14px;font-size:13px;">\n' +
666	'      <div class="trend-row"><span>📈 升级</span><strong style="color:#27ae60;">0人</strong><span class="det">-</span></div>\n' +
667	'      <div class="trend-row"><span>📉 降级</span><strong style="color:#e74c3c;">0人</strong><span class="det">-</span></div>\n' +
668	'      <div class="trend-row"><span>🆕 新进入</span><strong style="color:#3498db;">0人</strong><span class="det">-</span></div>\n' +
669	'      <div class="trend-row" style="border-bottom:none;"><span>⏸️ 流失</span><strong style="color:var(--text-secondary);">0人</strong><span class="det">-</span></div>\n' +
670	'    </div>\n  </div>\n</div>\n\n' +
671	'<div class="card">\n  <div class="card-hd">核心市场管道密度</div>\n' +
672	'  <table class="sub">\n    <tr><th>市场</th><th style="text-align:center;">客户数</th><th style="text-align:center;">S/A级</th><th style="text-align:center;">需行动</th></tr>\n    ' + marketRows + '\n  </table>\n</div>\n\n' +
673	'<div class="footer">管道看板 — 脚本自动生成，覆盖全部 ' + total + ' 客户 | 深度分析请新开对话 | 生成时间：' + timeStr + '</div>\n\n' +
674	'<div id="modal-overlay" class="modal-overlay" onclick="if(event.target===this)closeModal()">\n' +
675	'  <div class="modal-box"><div class="modal-hd"><span id="modal-title"></span><button class="modal-close" onclick="closeModal()">✕</button></div>\n' +
676	'    <div class="modal-body" id="modal-body"></div></div>\n</div>\n\n' +
677	'<script>\n' +
678	'window.MATRIX = ' + JSON.stringify(matrixJson) + ';\n' +
679	'window.ACTIONS = ' + JSON.stringify(actions) + ';\n' +
680	'function esc(s) { return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;"); }\n' +
681	'function gradeTag(g) {\n' +
682	'  var colors = {S:"#ff9f0a",A:"#0a84ff",B:"#636366",C:"#86868b",D:"#48484a"};\n' +
683	'  return \'<span style="background:\' + (colors[g]||\"#636366\") + \';color:\' + (g===\"S\"?\"#1d1d1f\":\"#fff\") + \';padding:1px 6px;border-radius:3px;font-size:10px;font-weight:600;margin-right:4px;\">\' + esc(g) + \'</span>\';\n' +
684	'}\n' +
685	'function prioIcon(p) {\n' +
686	'  var icons = {urgent:"🔴",soon:"🟡",watch:"🟢",idle:"⚪"};\n' +
687	'  return icons[p] || "";\n' +
688	'}\n' +
689	'function openModal(ls, q) {\n' +
690	'  var data = window.MATRIX[ls][q];\n' +
691	'  var action = window.ACTIONS[ls];\n' +
692	'  var actionText = action ? (action.byQuality[q] || action.defaultAction) : "";\n' +
